public static int lis(int[] arr) {
  Map<Integer, Integer> ends = new HashMap<>();
  int longest = 0;
  for (int val : arr) {
    // Find the largest prefix that ends with val
    List<Integer> prefix = ends.keySet().stream()
                               .filter(k -> k <= val)
                               .collect(Collectors.toList());
    int length = Collections.max(prefix);
    if (length == longest || val < arr[ends.get(length+1)]) {
      ends.put(length+1, val);
      longest = length + 1;
    }
  }
  return longest;
}

public static int lis(int[] arr) {
    int[] dp = new int[arr.length];
    int max = 0;
    for (int i=0; i<arr.length; i++) {
        dp[i] = 1;
        for (int j=0; j<i; j++) {
            if (arr[i] > arr[j] && dp[j]+1 > dp[i]) {
                dp[i] = dp[j] + 1;
            }
        }
        if (dp[i] > max) {
            max = dp[i];
        }
    }
    return max;
}

