public static Map<Node,Set<Node>> update(Map<Node,Set<Node>> groupByNode, Node vertex_u, Node vertex_v) {
        Set<Node> group_u = groupByNode.get(vertex_u);
        Set<Node> group_v = groupByNode.get(vertex_v);
        groupByNode.put(vertex_u, new HashSet<>(Arrays.asList(vertex_u.union(group_u))));
        groupByNode.put(vertex_v, new HashSet<>(Arrays.asList(vertex_v.union(group_v))));
        return groupByNode;
}

public static Set<WeightedEdge> minimum_spanning_tree(List<WeightedEdge> weightedEdges) {
    Set<WeightedEdge> minSpanningTree = new HashSet<>();
    Collections.sort(weightedEdges);
    Set<Node> groupByNode = new HashSet<>();
    for (WeightedEdge edge : weightedEdges) {
        Node vertex_u = edge.node1;
        Node vertex_v = edge.node2;
        if (!groupByNode.contains(vertex_u)){
            groupByNode.add(vertex_u);
        }
        if (!groupByNode.contains(vertex_v)){
            groupByNode.add(vertex_v);
        }
        if (groupByNode.size() != vertex_u.getParent().size()) {
            minSpanningTree.add(edge);
            groupByNode = merge(groupByNode, vertex_u, vertex_v);
        }
    }
    return minSpanningTree;
}

