class Solution {
    public int[] sortArray(int[] nums) {
        if (nums.length == 0) {
            return new int[0];
        }
        int pivot = nums[0];
        List<Integer> lesser = new ArrayList<>();
        List<Integer> greater = new ArrayList<>();
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] < pivot) {
                lesser.add(nums[i]);
            } else {
                greater.add(nums[i]);
            }
        }
        int[] middle = new int[greater.size()];
        lesser.add(pivot);
        int[] lesserSorted = sortArray(lesser.stream().mapToInt(i -> i).toArray());
        for (int i = 0; i < lesserSorted.length; i++) {
            middle[i] = lesserSorted[i];
        }
        int[] greaterSorted = sortArray(greater.stream().mapToInt(i -> i).toArray());
        for (int i = 0; i < greaterSorted.length; i++) {
            middle[i + lesserSorted.length] = greaterSorted[i];
        }
        return middle;
    }
}

