public static <T> List<T> merge_sort(List<T> list, Comparator<T> cmp) {
    if (list.size() <= 1) {
        return list;
    } else {
        int mid_point = (int) Math.floor(list.size() / 2);
        List<T> list_1 = merge_sort(list.subList(0, mid_point), cmp);
        List<T> list_2 = merge_sort(list.subList(mid_point, list.size()), cmp);
        return merge(list_1, list_2, cmp);
    }
}

