public static ArrayList<Integer> sieve(Integer max) {
    ArrayList<Integer> primes = new ArrayList<Integer>();
    for (int n=2; n<max+1; n++) {
        boolean p = true;
        for (int d : primes) {
            if (n%d == 0) {
                p = false;
                break;
            }
        }
        if (p) {
            primes.add(n);
        }
    }
    return primes;
}

